package main

func workflowV2CommandHelpCatalog() []commandHelp {
	common := []helpFlag{{Name: "--config", Value: "PATH", Description: "workflow v2 YAML config"}, {Name: "--var", Value: "KEY=VALUE", Description: "typed variable assignment; repeatable"}}
	selection := []helpFlag{{Name: "--id", Value: "ID", Description: "select an exact workflow run"}, {Name: "--config", Value: "PATH", Description: "select the newest run for this config"}}
	return []commandHelp{
		{Command: "workflow", Summary: "Run and manage persistent revision-aware DAG workflows.", Usage: []string{"tmact workflow example [--profile openspec]", "tmact workflow validate --config PATH [--var key=value] [--json]", "tmact workflow plan --config PATH [--var key=value] [--json]", "tmact workflow run --config PATH [--var key=value] [--once] [--execute]", "tmact workflow start --config PATH [--var key=value] [--execute]", "tmact workflow status (--id ID | --config PATH) [--json]", "tmact workflow logs (--id ID | --config PATH) [--follow]", "tmact workflow pause|resume (--id ID | --config PATH)", "tmact workflow retry --id ID --stage STAGE", "tmact workflow resolve --id ID --stage STAGE --outcome OUTCOME [--input key=value]", "tmact workflow report --dispatch-id ID --outcome OUTCOME [--body TEXT]", "tmact workflow stop (--id ID | --config PATH) --wait"}, Subcommands: []string{"example", "validate", "plan", "run", "start", "status", "logs", "pause", "resume", "retry", "resolve", "report", "stop"}, Safety: []string{"run and start only perform commands or tmux side effects when --execute is supplied.", "Permission and approval prompts are never accepted automatically."}, Notes: []string{"State and immutable config snapshots live under .tmact/workflows/<run-id>/.", "Agent reports use runner-issued durable dispatch IDs; agents never supply stage, attempt, or revision bindings."}},
		{Command: "workflow example", Summary: "Print a generic workflow v2 YAML or the built-in OpenSpec profile.", Usage: []string{"tmact workflow example [--profile openspec]"}, Flags: []helpFlag{{Name: "--profile", Value: "openspec", Description: "print the OpenSpec workflow expressed entirely as YAML"}}, Examples: []string{"tmact workflow example > workflow.yaml", "tmact workflow example --profile openspec > openspec-workflow.yaml"}},
		{Command: "workflow validate", Summary: "Strictly validate workflow v2 YAML, variables, references, conditions, and DAG shape.", Usage: []string{"tmact workflow validate --config PATH [--var key=value] [--json]"}, Flags: append(common, helpFlag{Name: "--json", Description: "print machine-readable validation output"})},
		{Command: "workflow plan", Summary: "Compute revisions and print the side-effect-free execution plan.", Usage: []string{"tmact workflow plan --config PATH [--var key=value] [--json]"}, Flags: append(common, helpFlag{Name: "--json", Description: "print machine-readable plan"})},
		{Command: "workflow run", Summary: "Run a workflow in the foreground; without --execute only print its plan.", Usage: []string{"tmact workflow run --config PATH [--var key=value] [--once] [--execute]"}, Flags: append(common, helpFlag{Name: "--once", Description: "perform one scheduler pass"}, helpFlag{Name: "--execute", Description: "perform command and tmux side effects"})},
		{Command: "workflow start", Summary: "Idempotently start a live workflow in the detached tmact-workflows session.", Usage: []string{"tmact workflow start --config PATH [--var key=value] [--execute]"}, Flags: append(common, helpFlag{Name: "--execute", Description: "create the detached runner and allow live effects"})},
		{Command: "workflow status", Summary: "Show persisted run and stage state.", Usage: []string{"tmact workflow status (--id ID | --config PATH) [--json]"}, Flags: append(selection, helpFlag{Name: "--json", Description: "print JSON"})},
		{Command: "workflow logs", Summary: "Read or follow durable workflow events.", Usage: []string{"tmact workflow logs (--id ID | --config PATH) [--follow]"}, Flags: append(selection, helpFlag{Name: "--follow", Description: "follow new events"})},
		{Command: "workflow pause", Summary: "Cooperatively pause scheduling new workflow stages.", Usage: []string{"tmact workflow pause (--id ID | --config PATH)"}, Flags: selection},
		{Command: "workflow resume", Summary: "Resume a paused workflow.", Usage: []string{"tmact workflow resume (--id ID | --config PATH)"}, Flags: selection},
		{Command: "workflow retry", Summary: "Retry one stage and invalidate its downstream stages.", Usage: []string{"tmact workflow retry --id ID --stage STAGE"}, Flags: []helpFlag{{Name: "--id", Value: "ID", Required: true, Description: "workflow run id"}, {Name: "--stage", Value: "STAGE", Required: true, Description: "stage id"}}},
		{Command: "workflow resolve", Summary: "Resolve a waiting human stage with a structured outcome and input.", Usage: []string{"tmact workflow resolve --id ID --stage STAGE --outcome OUTCOME [--input key=value]"}, Flags: append(selection, helpFlag{Name: "--stage", Value: "STAGE", Required: true, Description: "human stage"}, helpFlag{Name: "--outcome", Value: "OUTCOME", Required: true, Description: "allowed outcome"}, helpFlag{Name: "--input", Value: "KEY=VALUE", Description: "schema-checked input; repeatable"})},
		{Command: "workflow report", Summary: "Record an agent outcome for one durable dispatch ID.", Usage: []string{"tmact workflow report --dispatch-id ID --outcome OUTCOME [--body TEXT]"}, Flags: []helpFlag{{Name: "--dispatch-id", Value: "ID", Required: true, Description: "runner-issued durable dispatch id"}, {Name: "--outcome", Value: "OUTCOME", Required: true, Description: "stage-allowlisted outcome"}, {Name: "--body", Value: "TEXT", Description: "short evidence summary"}}},
		{Command: "workflow stop", Summary: "Request cooperative shutdown and wait for the runner.", Usage: []string{"tmact workflow stop (--id ID | --config PATH) --wait"}, Flags: append(selection, helpFlag{Name: "--wait", Required: true, Description: "wait for terminal state"})},
	}
}
